#include <stdio.h>

int main() {
    int start, end, divisor;
    long long sum = 0; // Use long long for sum to prevent overflow with large ranges/numbers

    // Read input values
    if (scanf("%d %d %d", &start, &end, &divisor) != 3) {
        // Handle potential input error, though problem statement implies valid input
        return 1;
    }

    // Loop through the range
    for (int i = start; i <= end; i++) {
        // Check if the current number is divisible by the divisor
        if (i % divisor == 0) {
            sum += i; // Add to sum if divisible
        }
    }

    // Print the final sum
    printf("%lld\n", sum);

    return 0;
}

#include <stdio.h>
#include <ctype.h> // Required for isupper, islower, isdigit

int main() {
    int c;
    int uppercase_count = 0;
    int lowercase_count = 0;
    int digit_count = 0;
    int other_count = 0;

    // Read characters until EOF
    while ((c = getchar()) != EOF) {
        if (isupper(c)) {
            uppercase_count++;
        } else if (islower(c)) {
            lowercase_count++;
        } else if (isdigit(c)) {
            digit_count++;
        } else {
            other_count++;
        }
    }

    // Print the counts
    printf("Uppercase: %d\n", uppercase_count);
    printf("Lowercase: %d\n", lowercase_count);
    printf("Digits: %d\n", digit_count);
    printf("Others: %d\n", other_count);

    return 0;
}

#include <stdio.h>

int main() {
    int N;
    int score;
    int count_A = 0;
    int count_B = 0;
    int count_C = 0;
    int count_D = 0;
    int count_F = 0;

    // Read the number of scores
    if (scanf("%d", &N) != 1) {
        return 1; // Input error
    }

    // Loop N times to read and categorize each score
    for (int i = 0; i < N; i++) {
        if (scanf("%d", &score) != 1) {
            return 1; // Input error
        }

        // Categorize the score using if-else if ladder
        if (score >= 90 && score <= 100) {
            count_A++;
        } else if (score >= 80 && score <= 89) {
            count_B++;
        } else if (score >= 70 && score <= 79) {
            count_C++;
        } else if (score >= 60 && score <= 69) {
            count_D++;
        } else if (score >= 0 && score <= 59) { // Explicitly check range for F
            count_F++;
        }
        // Assuming scores are always within 0-100 as per description
    }

    // Print the final counts for each grade
    printf("A: %d\n", count_A);
    printf("B: %d\n", count_B);
    printf("C: %d\n", count_C);
    printf("D: %d\n", count_D);
    printf("F: %d\n", count_F);

    return 0;
}
